// Process backlink changes
const items = $input.all().map(i => i.json);
const newLinks = items.filter(i => i.change_type === 'new');
const lostLinks = items.filter(i => i.change_type === 'lost');

if (items.length === 0) {
  return [{ json: { has_changes: false, summary: 'No backlink changes detected' } }];
}

// Calculate metrics
const newHighDA = newLinks.filter(l => l.domain_authority >= 50).length;
const lostHighDA = lostLinks.filter(l => l.domain_authority >= 50).length;

const changes = items.map(item => ({
  backlink_id: item.id,
  change_type: item.change_type,
  source_url: item.source_url,
  source_domain: item.source_domain,
  target_url: item.target_url,
  domain_authority: item.domain_authority,
  detected_date: new Date().toISOString().split('T')[0]
}));

return [{
  json: {
    has_changes: true,
    new_count: newLinks.length,
    lost_count: lostLinks.length,
    new_high_da: newHighDA,
    lost_high_da: lostHighDA,
    changes: changes,
    top_new: newLinks.sort((a, b) => (b.domain_authority || 0) - (a.domain_authority || 0)).slice(0, 5),
    top_lost: lostLinks.sort((a, b) => (b.domain_authority || 0) - (a.domain_authority || 0)).slice(0, 5)
  }
}];
